#!/usr/bin/env bash
#
# NT Cauldron installer wrapper
#
# Generated by compile.sh. This script is a self-decrypting wrapper: it contains
# an encrypted payload (the real setup.sh), prompts you for a passphrase obtained
# from NetTantra Keymint, decrypts the payload, and executes it.
#
# Usage:
#   curl -fsSL https://hsclr.net/nt-cauldron | bash

set -euo pipefail

KEYMINT_URL="https://keymint.nettantra.com"
PROJECT_SLUG="nt-cauldron"

# ===== browser open =====

PASSPHRASE_URL="${KEYMINT_URL}/projects/${PROJECT_SLUG}/passphrase"

echo ""
echo "This installer is encrypted. You need a passphrase from NetTantra Keymint to continue."
echo ""

open_browser() {
  if command -v open >/dev/null 2>&1; then
    open "$PASSPHRASE_URL" 2>/dev/null || true
  elif command -v xdg-open >/dev/null 2>&1; then
    xdg-open "$PASSPHRASE_URL" 2>/dev/null || true
  elif command -v python3 >/dev/null 2>&1; then
    python3 -c "import webbrowser; webbrowser.open('$PASSPHRASE_URL')" 2>/dev/null || true
  else
    echo "Could not open a browser automatically."
    echo "Visit this URL to get your passphrase:"
    echo ""
    echo "  ${PASSPHRASE_URL}"
    echo ""
  fi
}

open_browser

# ===== tty detection =====

if [ -t 0 ]; then
  TTY_IN=/dev/stdin
elif [ -r /dev/tty ]; then
  TTY_IN=/dev/tty
else
  echo "error: no controlling tty available" >&2
  echo "this wrapper must be run interactively, not piped from a file." >&2
  exit 1
fi

# ===== read passphrase =====

while true; do
  printf "Enter passphrase from NetTantra Keymint (input hidden): " > /dev/tty
  IFS= read -rs PASSPHRASE < "$TTY_IN" || PASSPHRASE=""
  printf "\n" > /dev/tty
  if [ -z "$PASSPHRASE" ]; then
    echo "Passphrase cannot be empty." >&2
    continue
  fi
  break
done

# ===== prerequisite checks =====

command -v openssl >/dev/null 2>&1 || { echo "error: openssl not found on PATH" >&2; exit 1; }
command -v base64 >/dev/null 2>&1 || { echo "error: base64 not found on PATH" >&2; exit 1; }

# ===== decrypt and execute =====

export DECRYPT_PASS="$PASSPHRASE"

PAYLOAD='
'

printf '%s\n' "$PAYLOAD" | base64 -d | openssl aes-256-cbc -d -salt -pbkdf2 -pass env:DECRYPT_PASS | bash

DECRYPT_EXIT=$?
unset PASSPHRASE DECRYPT_PASS PAYLOAD

if [ $DECRYPT_EXIT -ne 0 ]; then
  echo "error: decryption failed (wrong passphrase or corrupt payload)." >&2
  echo "rerun this installer and request a new passphrase from NetTantra Keymint." >&2
  exit $DECRYPT_EXIT
fi
